const user = $('Get User').item.json;
const log = $('Get Today Log').item.json;
const trends = $('Get 7-Day Trend').all().map(i => i.json);

const trendText = trends.map(d =>
  `  ${d.log_date}: ${d.calories_consumed||0} kcal | Sleep ${d.sleep_hours||'?'}h | Energy ${d.energy_level||'?'}/10 | Workout ${d.workout_done ? '✅' : '❌'} | Steps ${d.steps||0}`
).join('\n') || 'No previous data yet.';

const systemPrompt = `You are FitBuddy AI — an expert, encouraging personal fitness and nutrition coach. Always be specific, actionable, and use the user's actual data. Format for Telegram using emojis. Never give medical diagnoses.`;

const userPrompt = `Analyze this user's data and generate their daily FitBuddy report.

USER: ${user.first_name}, Age ${user.age}, ${user.gender}, ${user.weight_kg}kg/${user.height_cm}cm
Goal: ${user.goal} | Daily target: ${user.daily_calorie_target} kcal | Activity: ${user.activity_level}

TODAY (${log.log_date||'today'}):
- Sleep: ${log.sleep_hours||0}h | Energy: ${log.energy_level||5}/10 | Mood: ${log.mood||'okay'}
- Food: ${log.food_description||'Not provided'} (~${log.calories_consumed||0} kcal)
- Protein: ${log.protein_g||0}g | Carbs: ${log.carbs_g||0}g | Fat: ${log.fat_g||0}g
- Workout: ${log.workout_description||'Rest day'} | Steps: ${log.steps||0} | Water: ${log.water_ml||0}ml

7-DAY TREND:
${trendText}

Generate these sections with the exact emoji headers:

🍽️ NUTRITION PLAN
Specific meal plan for tomorrow targeting ${user.daily_calorie_target} kcal. Include breakfast, lunch, dinner, snack with portions.

🏋️ WORKOUT PLAN
Specific workout for tomorrow matching energy level ${log.energy_level||5}/10 and goal ${user.goal}.

🔄 HEALTHY SUBSTITUTES
3 specific swaps from today's food. Format: [Original] → [Substitute] — [Why]

📈 PROGRESS SNAPSHOT
2 honest, encouraging sentences about their trend.

💬 DAILY MOTIVATION
One personalized sentence for their situation today.`;

return [{ json: {
  systemPrompt,
  userPrompt,
  telegramId: user.telegram_id,
  userId: user.id,
  userName: user.first_name
} }];

const aiResponse = $json.choices?.[0]?.message?.content || 'No response generated.';
const prev = $('Compose Prompt').item.json;
return [{ json: { aiResponse, telegramId: prev.telegramId, userId: prev.userId } }];
